func searchSummary(search viewmodel.PersonRecordSearch) string {
	if search.Mode != "advanced" {
		if search.Browse {
			return "Browse: alphabetical list"
		}
		if strings.TrimSpace(search.Query) == "" {
			return ""
		}
		return fmt.Sprintf("Search: %q", search.Query)
	}

	parts := []string{}
	if search.DisplayID != "" {
		parts = append(parts, "Display ID "+search.DisplayID)
	}
	if search.EntryType != "" {
		switch strings.ToLower(strings.TrimSpace(search.EntryType)) {
		case "wife":
			parts = append(parts, "Entry type Wife")
		case "widow":
			parts = append(parts, "Entry type Widow")
		default:
			parts = append(parts, "Entry type Soldier")
		}
	}
	if search.FirstName != "" {
		parts = append(parts, "First name "+search.FirstName)
	}
	if search.MiddleName != "" {
		parts = append(parts, "Middle name "+search.MiddleName)
	}
	if search.LastName != "" {
		parts = append(parts, "Last name "+search.LastName)
	}
	if search.MaidenName != "" {
		parts = append(parts, "Maiden name "+search.MaidenName)
	}
	if search.Rank != "" {
		parts = append(parts, "Rank "+search.Rank)
	}
	if search.RankIn != "" {
		parts = append(parts, "Rank in "+search.RankIn)
	}
	if search.RankOut != "" {
		parts = append(parts, "Rank out "+search.RankOut)
	}
	if search.Unit != "" {
		parts = append(parts, "Unit "+search.Unit)
	}
	if search.SourceRecordType != "" {
		parts = append(parts, "Source record type "+search.SourceRecordType)
	}
	if search.PensionState != "" {
		parts = append(parts, "Pension state "+search.PensionState)
	}
	if search.ConfederateHomeStatus != "" {
		parts = append(parts, "Confederate home status "+search.ConfederateHomeStatus)
	}
	if search.ConfederateHomeName != "" {
		parts = append(parts, "Confederate home name "+search.ConfederateHomeName)
	}
	if search.BuriedIn != "" {
		parts = append(parts, "Buried in "+search.BuriedIn)
	}
	if search.ReviewStatus != "" {
		switch strings.ToLower(strings.TrimSpace(search.ReviewStatus)) {
		case "clean":
			parts = append(parts, "Clean person records only")
		case "review":
			parts = append(parts, "Review queue only")
		}
	}
	if search.BirthDate != "" {
		parts = append(parts, "Birth date "+search.BirthDate)
	}
	if search.BirthYear != "" && search.BirthYearTo != "" {
		parts = append(parts, "Birth year "+search.BirthYear+"-"+search.BirthYearTo)
	} else if search.BirthYear != "" {
		parts = append(parts, "Birth year "+search.BirthYear)
	} else if search.BirthYearTo != "" {
		parts = append(parts, "Birth year through "+search.BirthYearTo)
	}
	if search.DeathDate != "" {
		parts = append(parts, "Death date "+search.DeathDate)
	}
	if search.DeathYear != "" && search.DeathYearTo != "" {
		parts = append(parts, "Death year "+search.DeathYear+"-"+search.DeathYearTo)
	} else if search.DeathYear != "" {
		parts = append(parts, "Death year "+search.DeathYear)
	} else if search.DeathYearTo != "" {
		parts = append(parts, "Death year through "+search.DeathYearTo)
	}
	if search.DeathMonth != "" {
		parts = append(parts, "Death month "+search.DeathMonth)
	}
	if search.DeathDay != "" {
		parts = append(parts, "Death day "+search.DeathDay)
	}
	if len(parts) == 0 {
		return "Advanced search"
	}
	return "Advanced filters: " + strings.Join(parts, ", ")
}

func reviewStatusLabel(s viewmodel.PersonRecord) string {
	if s.NeedsReview {
		return "Needs Review"
	}
	return "Clean"
}

func soldierFullName(s viewmodel.PersonRecord) string {
	return s.GetFullName()
}

func isSoldierEntry(s viewmodel.PersonRecord) bool {
	return strings.TrimSpace(s.EntryType) == "" || s.EntryType == "soldier"
}

func soldierHasCamaraderie(s viewmodel.PersonRecord) bool {
	return isSoldierEntry(s) && strings.TrimSpace(s.Unit) != ""
}

func soldierHasTimeline(s viewmodel.PersonRecord) bool {
	if !isSoldierEntry(s) {
		return false
	}
	if strings.TrimSpace(s.BirthDate) != "" || strings.TrimSpace(s.BirthInfo) != "" || strings.TrimSpace(s.DeathDate) != "" {
		return true
	}
	if s.DeathYear > 0 || s.DeathMonth > 0 || s.DeathDay > 0 {
		return true
	}
	return len(s.SourceRecords) > 0
}

func soldierStateResearchPackLabel(s viewmodel.PersonRecord) string {
	if trimmed := strings.TrimSpace(s.PensionState); trimmed != "" {
		return trimmed
	}
	_, state := soldierBirthInfoResearchPackLabels(s.BirthInfo)
	return state
}

func soldierCountyResearchPackLabel(s viewmodel.PersonRecord) string {
	county, _ := soldierBirthInfoResearchPackLabels(s.BirthInfo)
	return county
}

func soldierHasResearchPack(s viewmodel.PersonRecord) bool {
	return soldierStateResearchPackLabel(s) != "" || soldierCountyResearchPackLabel(s) != ""
}

func soldierBirthInfoResearchPackLabels(value string) (string, string) {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return "", ""
	}
	countyStatePattern := regexp.MustCompile(`(?i)\b(?:in\s+)?([A-Za-z .'-]+ County),\s*([A-Za-z .'-]+)\b`)
	if match := countyStatePattern.FindStringSubmatch(trimmed); len(match) == 3 {
		county := strings.TrimSpace(match[1])
		if len(county) > 3 && strings.EqualFold(county[:3], "in ") {
			county = strings.TrimSpace(county[3:])
		}
		return county, strings.Trim(strings.TrimSpace(match[2]), ". ")
	}
	stateTailPattern := regexp.MustCompile(`(?i),\s*([A-Za-z .'-]+)\.?\s*$`)
	if match := stateTailPattern.FindStringSubmatch(trimmed); len(match) == 2 {
		return "", strings.Trim(strings.TrimSpace(match[1]), ". ")
	}
	return "", ""
}

func isWidowEntry(s viewmodel.PersonRecord) bool {
	return s.EntryType == "widow"
}

func entryBadgeLabel(s viewmodel.PersonRecord) string {
	switch s.EntryType {
	case "wife":
		return "Wife"
	case "widow":
		return "Widow"
	default:
		return "Soldier"
	}
}

func detailHeading(s viewmodel.PersonRecord) string {
	name := strings.TrimSpace(soldierFullName(s))
	if isSoldierEntry(s) {
		rank := strings.TrimSpace(detailDisplayRank(s))
		if rank == "" {
			return name
		}
		if name == "" {
			return rank
		}
		return rank + " " + name
	}
	if name != "" {
		return name
	}
	return entryBadgeLabel(s)
}

func detailSubheading(s viewmodel.PersonRecord) string {
	if isSoldierEntry(s) {
		return strings.TrimSpace(s.Unit)
	}
	if strings.TrimSpace(s.SpouseName) != "" {
		return "Married to " + strings.TrimSpace(s.SpouseName)
	}
	return strings.TrimSpace(s.MaidenName)
}

func relationshipLabel(s viewmodel.PersonRecord) string {
	name := strings.TrimSpace(s.SpouseName)
	displayID := strings.TrimSpace(s.SpouseDisplayID)
	switch {
	case name != "" && displayID != "":
		return name + " (" + displayID + ")"
	case name != "":
		if s.LinkedSoldierID > 0 {
			return fmt.Sprintf("%s (DB ID %d)", name, s.LinkedSoldierID)
		}
		return name
	case displayID != "":
		return displayID
	case s.LinkedSoldierID > 0:
		return fmt.Sprintf("DB ID %d", s.LinkedSoldierID)
	default:
		return "Not recorded"
	}
}

func backButtonLabel(s viewmodel.PersonRecord) string {
	if strings.TrimSpace(s.BackLinkLabel) != "" {
		return s.BackLinkLabel
	}
	return "Back"
}

func soldierDetailBackHref(s viewmodel.PersonRecord) string {
	if strings.TrimSpace(s.BackLinkURL) != "" {
		return strings.TrimSpace(s.BackLinkURL)
	}
	return "/soldiers"
}

func detailDisplayRank(s viewmodel.PersonRecord) string {
	if trimmed := strings.TrimSpace(s.RankOut); trimmed != "" {
		return trimmed
	}
	if trimmed := strings.TrimSpace(s.Rank); trimmed != "" {
		return trimmed
	}
	return strings.TrimSpace(s.RankIn)
}

